# Shopify HMAC Verification - Webhooks and Events
created: 2025-07-22, last updated: 2026-05-03, [Read more](https://community.shopify.dev/t/shopify-hmac-verification/19654)

Are you using Node.js?
You can try this code
```
import crypto from 'crypto';
export function verifyShopifyWebhook(secret) {
return async (req, res, next) => {
try {
const hmacHeader = req.get('X-Shopify-Hmac-Sha256');
const rawBody = await getRawBody(req);
const generatedHmac = crypto
.createHmac('sha256', secret)
.update(rawBody, 'utf8')
.digest('base64');
if (crypto.timingSafeEqual(Buffer.from(generatedHmac), Buffer.from(hmacHeader))) {
req.rawBody = rawBody;
next();
} else {
return res.status(401).send('HMAC validation failed');
}
} catch (error) {
return res.status(500).send('Server error');
}
};
}
// Helper function to get raw body
function getRawBody(req) {
return new Promise((resolve, reject) => {
let data = '';
req.setEncoding('utf8');
req.on('data', chunk => {
data += chunk;
...
req.on('error', err => reject(err));
});
}

